consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
/* ==========================================================================
   Tag — hover/pressed via direct background-color + color-mix().
   No pseudo-element overlays.
   ========================================================================== */

.tag {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--dimension-radius-050);
  box-sizing: border-box;
  color: var(--color-foreground-primary);
  position: relative;

  /* Interaction — ghost defaults */
  --_hover-bg: var(--color-interaction-hover);
  --_pressed-bg: var(--color-interaction-pressed);
}

/* ==========================================================================
   Sizes
   md  28px — no size-350 token, expressed as 7/2 × base
   sm  20px — size-250
   xs  12px — size-150
   ========================================================================== */

.sizeMd { height: calc(var(--dimension-size-base) * 7 / 2); padding: 0 var(--dimension-space-075); gap: 0; }
.sizeSm { height: var(--dimension-size-250);                padding: 0 var(--dimension-space-050); gap: 0; }
.sizeXs { height: var(--dimension-size-150);                padding: 0 var(--dimension-space-012); gap: 0; }

/* ==========================================================================
   Rounded
   ========================================================================== */

.rounded { border-radius: var(--dimension-radius-half); }

/*
 * Pill padding correction — add space-050 to sides that have no content anchor.
 * Applied by Tag.tsx based on whether a leading icon or trailing remove is present:
 *   no leading icon  → roundedLeft{Size}   (left side is bare label text)
 *   no trailing icon → roundedRight{Size}  (right side is bare label text)
 * Placed after size rules so same-specificity cascade wins correctly.
 */

/* MD — base: space-075 */
.roundedLeftMD  { padding-left:  calc(var(--dimension-space-075) + var(--dimension-space-050)); }
.roundedRightMD { padding-right: calc(var(--dimension-space-075) + var(--dimension-space-050)); }

/* SM — base: space-050 */
.roundedLeftSM  { padding-left:  calc(var(--dimension-space-050) + var(--dimension-space-050)); }
.roundedRightSM { padding-right: calc(var(--dimension-space-050) + var(--dimension-space-050)); }

/* XS — base: space-012 (1px) */
.roundedLeftXS  { padding-left:  calc(var(--dimension-space-012) + var(--dimension-space-050)); }
.roundedRightXS { padding-right: calc(var(--dimension-space-012) + var(--dimension-space-050)); }

/*
 * Icon-edge padding correction — when an icon (leading or remove) sits on a
 * side, that side's padding should match the top/bottom optical gap:
 *   (height − icon_size) / 2
 *
 *   md: (28 − 20) / 2 = 4px  → space-050
 *   sm: (20 − 16) / 2 = 2px  → space-025
 *   xs: (12 − 12) / 2 = 0px  → 0
 *
 * Applied by Tag.tsx: iconLeft when Icon present, iconRight when removable.
 * Placed after size + rounded rules so same-specificity cascade wins.
 */
.iconLeftMD  { padding-left:  var(--dimension-space-050); }
.iconRightMD { padding-right: var(--dimension-space-050); }

.iconLeftSM  { padding-left:  var(--dimension-space-025); }
.iconRightSM { padding-right: var(--dimension-space-025); }

.iconLeftXS  { padding-left:  0; }
.iconRightXS { padding-right: 0; }

/* ==========================================================================
   Background context — parent surface awareness
   ========================================================================== */

.onMedium {
  --_hover-bg: var(--color-interaction-on-medium-background-hover);
  --_pressed-bg: var(--color-interaction-on-medium-background-pressed);
}

.onBold {
  --_hover-bg: var(--color-interaction-on-bold-background-hover);
  --_pressed-bg: var(--color-interaction-on-bold-background-pressed);
}

.onStrong {
  --_hover-bg: var(--color-interaction-on-strong-background-hover);
  --_pressed-bg: var(--color-interaction-on-strong-background-pressed);
}

.onAlwaysDark {
  --_hover-bg: var(--color-always-dark-interaction-hover);
  --_pressed-bg: var(--color-always-dark-interaction-pressed);
}

/* ==========================================================================
   Elevation
   none     — filled intent bg, no border, no shadow  (default)
   flat     — transparent bg + intent-coloured border ring
   elevated — filled intent bg + elevated shadow
   ========================================================================== */

/* elevationNone — no extra chrome needed, intent+contrast classes handle fill */

.elevationFlat {
  background-color: transparent !important;
  box-shadow: inset 0 0 0 var(--dimension-stroke-width-015) currentColor;
}

/* Flat: no background — use on-surface fg tokens matched to the contrast level.
   The border ring is currentColor so it follows text color automatically.
   3-class specificity beats the 2-class intent+contrast filled rules above. */

.elevationFlat.intentNeutral.contrastBold   { color: var(--color-foreground-bold-neutral);   }
.elevationFlat.intentBrand.contrastBold     { color: var(--color-foreground-bold-brand);     }
.elevationFlat.intentAi.contrastBold        { color: var(--color-foreground-bold-ai);        }
.elevationFlat.intentNegative.contrastBold  { color: var(--color-foreground-bold-negative);  }
.elevationFlat.intentWarning.contrastBold   { color: var(--color-foreground-bold-warning);   }
.elevationFlat.intentCaution.contrastBold   { color: var(--color-foreground-bold-caution);   }
.elevationFlat.intentPositive.contrastBold  { color: var(--color-foreground-bold-positive);  }

.elevationFlat.intentNeutral.contrastStrong   { color: var(--color-foreground-strong-neutral);   }
.elevationFlat.intentBrand.contrastStrong     { color: var(--color-foreground-strong-brand);     }
.elevationFlat.intentAi.contrastStrong        { color: var(--color-foreground-strong-ai);        }
.elevationFlat.intentNegative.contrastStrong  { color: var(--color-foreground-strong-negative);  }
.elevationFlat.intentWarning.contrastStrong   { color: var(--color-foreground-strong-warning);   }
.elevationFlat.intentCaution.contrastStrong   { color: var(--color-foreground-strong-caution);   }
.elevationFlat.intentPositive.contrastStrong  { color: var(--color-foreground-strong-positive);  }

.elevationFlat.intentNeutral.contrastMedium   { color: var(--color-foreground-medium-neutral);   }
.elevationFlat.intentBrand.contrastMedium     { color: var(--color-foreground-medium-brand);     }
.elevationFlat.intentAi.contrastMedium        { color: var(--color-foreground-medium-ai);        }
.elevationFlat.intentNegative.contrastMedium  { color: var(--color-foreground-medium-negative);  }
.elevationFlat.intentWarning.contrastMedium   { color: var(--color-foreground-medium-warning);   }
.elevationFlat.intentCaution.contrastMedium   { color: var(--color-foreground-medium-caution);   }
.elevationFlat.intentPositive.contrastMedium  { color: var(--color-foreground-medium-positive);  }

.elevationFlat.intentNeutral.contrastFaint   { color: var(--color-foreground-faint-neutral);   }
.elevationFlat.intentBrand.contrastFaint     { color: var(--color-foreground-faint-brand);     }
.elevationFlat.intentAi.contrastFaint        { color: var(--color-foreground-faint-ai);        }
.elevationFlat.intentNegative.contrastFaint  { color: var(--color-foreground-faint-negative);  }
.elevationFlat.intentWarning.contrastFaint   { color: var(--color-foreground-faint-warning);   }
.elevationFlat.intentCaution.contrastFaint   { color: var(--color-foreground-faint-caution);   }
.elevationFlat.intentPositive.contrastFaint  { color: var(--color-foreground-faint-positive);  }

.elevationElevated { box-shadow: var(--effect-elevation-elevated-sm); }

/* ==========================================================================
   Intent + contrast — strong
   ========================================================================== */

.intentNeutral.contrastStrong  { background-color: var(--color-background-strong-neutral);  color: var(--color-foreground-medium-neutral);  }
.intentBrand.contrastStrong    { background-color: var(--color-background-strong-brand);    color: var(--color-foreground-medium-brand);    }
.intentAi.contrastStrong       { background-color: var(--color-background-strong-ai);       color: var(--color-foreground-medium-ai);       }
.intentNegative.contrastStrong { background-color: var(--color-background-strong-negative); color: var(--color-foreground-medium-negative); }
.intentWarning.contrastStrong  { background-color: var(--color-background-strong-warning);  color: var(--color-foreground-medium-warning);  }
.intentCaution.contrastStrong  { background-color: var(--color-background-strong-caution);  color: var(--color-foreground-medium-caution);  }
.intentPositive.contrastStrong { background-color: var(--color-background-strong-positive); color: var(--color-foreground-medium-positive); }

/* ==========================================================================
   Intent + contrast — bold
   ========================================================================== */

.intentNeutral.contrastBold  { background-color: var(--color-background-bold-neutral);  color: var(--color-foreground-on-bold-background-primary); }
.intentBrand.contrastBold    { background-color: var(--color-background-bold-brand);    color: var(--color-foreground-on-bold-background-primary); }
.intentAi.contrastBold       { background-color: var(--color-background-bold-ai);       color: var(--color-foreground-on-bold-background-primary); }
.intentNegative.contrastBold { background-color: var(--color-background-bold-negative); color: var(--color-foreground-on-bold-background-primary); }
.intentWarning.contrastBold  { background-color: var(--color-background-bold-warning);  color: var(--color-foreground-on-bold-background-primary); }
.intentCaution.contrastBold  { background-color: var(--color-background-bold-caution);  color: var(--color-foreground-on-bold-background-primary); }
.intentPositive.contrastBold { background-color: var(--color-background-bold-positive); color: var(--color-foreground-on-bold-background-primary); }

/* ==========================================================================
   Intent + contrast — medium
   ========================================================================== */

.intentNeutral.contrastMedium  { background-color: var(--color-background-medium-neutral);  color: var(--color-foreground-strong-neutral);  }
.intentBrand.contrastMedium    { background-color: var(--color-background-medium-brand);    color: var(--color-foreground-strong-brand);    }
.intentAi.contrastMedium       { background-color: var(--color-background-medium-ai);       color: var(--color-foreground-strong-ai);       }
.intentNegative.contrastMedium { background-color: var(--color-background-medium-negative); color: var(--color-foreground-strong-negative); }
.intentWarning.contrastMedium  { background-color: var(--color-background-medium-warning);  color: var(--color-foreground-strong-warning);  }
.intentCaution.contrastMedium  { background-color: var(--color-background-medium-caution);  color: var(--color-foreground-strong-caution);  }
.intentPositive.contrastMedium { background-color: var(--color-background-medium-positive); color: var(--color-foreground-strong-positive); }

/* ==========================================================================
   Intent + contrast — faint
   ========================================================================== */

.intentNeutral.contrastFaint  { background-color: var(--color-background-faint-neutral);  color: var(--color-foreground-bold-neutral);  }
.intentBrand.contrastFaint    { background-color: var(--color-background-faint-brand);    color: var(--color-foreground-bold-brand);    }
.intentAi.contrastFaint       { background-color: var(--color-background-faint-ai);       color: var(--color-foreground-bold-ai);       }
.intentNegative.contrastFaint { background-color: var(--color-background-faint-negative); color: var(--color-foreground-bold-negative); }
.intentWarning.contrastFaint  { background-color: var(--color-background-faint-warning);  color: var(--color-foreground-bold-warning);  }
.intentCaution.contrastFaint  { background-color: var(--color-background-faint-caution);  color: var(--color-foreground-bold-caution);  }
.intentPositive.contrastFaint { background-color: var(--color-background-faint-positive); color: var(--color-foreground-bold-positive); }

/* ==========================================================================
   Interactive (clickable / filter-chip)
   ========================================================================== */

.interactive {
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  outline: none;
}

.interactive:hover  { background-color: var(--_hover-bg); }
.interactive:active { background-color: var(--_pressed-bg); }

.interactive:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

/* ==========================================================================
   Pressed / selected (filter-chip active state)
   Always brand — same language as ToggleButton
   ========================================================================== */

.tag.pressed {
  background-color: var(--color-background-faint-brand) !important;
  color: var(--color-foreground-bold-brand) !important;
  border-color: transparent !important;
}

/* ==========================================================================
   Remove button — keeps ::before overlay for its own isolated hit area
   ========================================================================== */

.removable { gap: var(--dimension-space-025); }
.sizeXs.removable { gap: 0; }

.removeButton {
  padding: 0; margin: 0; border: none; background: none;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; color: inherit; flex-shrink: 0;
  position: relative; border-radius: var(--dimension-radius-050);
}

.removeButton::before {
  content: ''; position: absolute; inset: -2px;
  border-radius: var(--dimension-radius-025);
  background-color: transparent;
  transition: var(--effect-transition-interaction-background-short-2);
  pointer-events: none;
}

.removeButton:hover::before  { background-color: var(--color-interaction-hover); }
.removeButton:active::before { background-color: var(--color-interaction-pressed); }

/* SM — 1px gap, inset -1px → 18×18 hover area */
.sizeSm .removeButton::before { inset: -1px; border-radius: 3px; }

/* XS — flush, inset 0 → 12×12 hover area matching tag radius */
.sizeXs .removeButton::before { inset: 0; border-radius: var(--dimension-radius-050); }

.rounded .removeButton,
.rounded .removeButton::before { border-radius: var(--dimension-radius-half); }

/* ==========================================================================
   Disabled
   ========================================================================== */

.inactive { opacity: 0.5; pointer-events: none; cursor: not-allowed; }

import React, { forwardRef } from 'react';
import { cn } from '@/utils/cn';
import { Text } from '@/components/Text';
import { LabelWrap } from '@/components/LabelWrap';
import { CrossUI } from '@ds-mo/icons';
import type { IconComponent } from '@/types/icons';
import styles from './Tag.module.css';

export type TagIntent      = 'neutral' | 'brand' | 'ai' | 'negative' | 'warning' | 'caution' | 'positive';
export type TagContrast    = 'strong' | 'bold' | 'medium' | 'faint';
export type TagElevation   = 'none' | 'flat' | 'elevated';
export type TagSize        = 'md' | 'sm' | 'xs';
export type TagBackground  = 'faint' | 'medium' | 'bold' | 'strong' | 'always-dark';

export interface TagProps {
  label: string;
  intent?: TagIntent;
  contrast?: TagContrast;
  /**
   * Visual chrome level.
   *   none     — filled with intent bg, no border, no shadow  [default]
   *   flat     — transparent bg + intent-coloured border ring
   *   elevated — filled with intent bg + elevated shadow
   */
  elevation?: TagElevation;
  size?: TagSize;
  rounded?: boolean;
  /** Leading icon component. */
  icon?: IconComponent;
  removable?: boolean;
  onRemove?: () => void;
  /** Override the default CrossUI remove icon. */
  removeIcon?: IconComponent;
  maxWidth?: string | number;
  inactive?: boolean;
  /** Parent surface context. Adjusts hover tokens for tags on colored backgrounds. */
  background?: TagBackground;
  /** Makes the tag clickable. Pair with pressed/onPressedChange for filter-chip behaviour. */
  onClick?: () => void;
  pressed?: boolean;
  onPressedChange?: (pressed: boolean) => void;
  className?: string;
}

const ICON_SIZE: Record<TagSize, number> = { md: 20, sm: 16, xs: 12 };

const TEXT_STYLE_MAP: Record<TagSize, string> = {
  md: 'text-body-medium',
  sm: 'text-body-small',
  xs: 'text-caption',
};

export const Tag = forwardRef<HTMLDivElement, TagProps>(
  (
    {
      label,
      intent    = 'neutral',
      contrast  = 'faint',
      elevation = 'none',
      size      = 'md',
      rounded   = false,
      icon: Icon,
      removable = false,
      onRemove,
      removeIcon: RemoveIcon,
      maxWidth,
      inactive  = false,
      background,
      onClick,
      pressed,
      onPressedChange,
      className,
    },
    ref
  ) => {
    const isInteractive  = !!onClick || !!onPressedChange;
    const hasRemove      = removable && !!onRemove;
    const iconSize       = ICON_SIZE[size];
    const textStyle      = TEXT_STYLE_MAP[size];
    const elevKey        = elevation.charAt(0).toUpperCase() + elevation.slice(1);
    const sizeKey        = size.toUpperCase() as 'MD' | 'SM' | 'XS';

    const classes = cn(
      styles.tag,
      styles[`intent${intent.charAt(0).toUpperCase() + intent.slice(1)}`],
      styles[`contrast${contrast.charAt(0).toUpperCase() + contrast.slice(1)}`],
      styles[`elevation${elevKey}`],
      styles[`size${size.charAt(0).toUpperCase() + size.slice(1)}`],
      rounded    && styles.rounded,
      // Pill padding correction — extra space-050 on bare sides (no content anchor)
      rounded && !Icon      && (styles as Record<string, string>)[`roundedLeft${sizeKey}`],
      rounded && !hasRemove && (styles as Record<string, string>)[`roundedRight${sizeKey}`],
      // Icon-edge correction — reduce padding to (height − icon) / 2 on icon sides
      !!Icon    && (styles as Record<string, string>)[`iconLeft${sizeKey}`],
      hasRemove && (styles as Record<string, string>)[`iconRight${sizeKey}`],
      removable  && styles.removable,
      isInteractive && styles.interactive,
      background && background !== 'faint' && styles[
        background === 'always-dark' ? 'onAlwaysDark'
          : `on${background.charAt(0).toUpperCase() + background.slice(1)}`
      ],
      inactive   && styles.inactive,
      pressed    && styles.pressed,
      className,
    );

    const style = maxWidth != null
      ? { maxWidth: typeof maxWidth === 'number' ? `${maxWidth}px` : maxWidth }
      : undefined;

    const handleInteract = isInteractive && !inactive
      ? () => {
          onPressedChange?.(!pressed);
          onClick?.();
        }
      : undefined;

    const handleKeyDown = isInteractive && !inactive
      ? (e: React.KeyboardEvent<HTMLDivElement>) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            onPressedChange?.(!pressed);
            onClick?.();
          }
        }
      : undefined;

    return (
      <div
        ref={ref}
        className={classes}
        style={style}
        onClick={handleInteract}
        onKeyDown={handleKeyDown}
        role={isInteractive ? 'button' : undefined}
        tabIndex={isInteractive && !inactive ? 0 : undefined}
        aria-pressed={onPressedChange != null ? pressed : undefined}
        aria-disabled={inactive || undefined}
      >
        {Icon && <Icon size={iconSize} />}
        <LabelWrap size={size}>
          <Text variant={textStyle as never} as="span" color="inherit">
            {label}
          </Text>
        </LabelWrap>
        {removable && onRemove && (
          <button
            type="button"
            className={styles.removeButton}
            onClick={(e) => { e.stopPropagation(); onRemove(); }}
            aria-label={`Remove ${label}`}
            tabIndex={-1}
          >
            {RemoveIcon ? <RemoveIcon size={iconSize} /> : <CrossUI size={iconSize} />}
          </button>
        )}
      </div>
    );
  }
);

Tag.displayName = 'Tag';
